     1→import { neon, type NeonQueryFunction } from "@neondatabase/serverless";
     2→import { drizzle, type NeonHttpDatabase } from "drizzle-orm/neon-http";
     3→import * as schema from "./schema";
     4→
     5→// Check if database is configured
     6→const isDatabaseConfigured = () => {
     7→  const url = process.env.DATABASE_URL;
     8→  return !!url && url !== "postgresql://placeholder";
     9→};
    10→
    11→// Lazy initialization to avoid build-time errors
    12→let _db: NeonHttpDatabase<typeof schema> | null = null;
    13→let _sql: NeonQueryFunction<boolean, boolean> | null = null;
    14→
    15→function getDatabase(): NeonHttpDatabase<typeof schema> {
    16→  if (!_db) {
    17→    if (!isDatabaseConfigured()) {
    18→      throw new Error(
    19→        "Database not configured. Please set DATABASE_URL environment variable."
    20→      );
    21→    }
    22→    _sql = neon(process.env.DATABASE_URL!);
    23→    _db = drizzle(_sql, { schema });
    24→  }
    25→  return _db;
    26→}
    27→
    28→// Export a proxy that lazily initializes the database
    29→export const db = new Proxy({} as NeonHttpDatabase<typeof schema>, {
    30→  get(_target, prop) {
    31→    const database = getDatabase();
    32→    const value = database[prop as keyof typeof database];
    33→    if (typeof value === "function") {
    34→      return value.bind(database);
    35→    }
    36→    return value;
    37→  },
    38→});
    39→
    40→// Export getDb function for explicit access
    41→export function getDb(): NeonHttpDatabase<typeof schema> {
    42→  return getDatabase();
    43→}
    44→
    45→// Export schema for use in queries
    46→export { schema };
    47→
    48→// Export RLS utilities
    49→export * from "./rls";
    50→
    51→// Export commonly used types
    52→export type Database = NeonHttpDatabase<typeof schema>;
    53→

