   668→    // Mention resolvers - SELECT * FROM mentions WHERE id = $1
   669→    mention: async (_: unknown, { id }: { id: string }, context: GraphQLContext) => {
   670→      context.requireAuth();
   671→      try {
   672→        const result = await db.select().from(schema.brandMentions).where(eq(schema.brandMentions.id, id)).limit(1);
   673→        if (!result[0]) return null;
   674→        const mention = result[0];
   675→        return {
   676→          ...mention,
   677→          sentimentScore: mention.sentiment === "positive" ? 0.8 : mention.sentiment === "negative" ? 0.2 : 0.5,
   678→          isRecommendation: mention.promptCategory === "recommendation",
   679→          competitorMentioned: (mention.competitors || []).length > 0,
   680→        };
   681→      } catch (error) {
   682→        console.error("Database error fetching mention:", error);
   683→        throw new Error("Failed to fetch mention. Please try again later.");
   684→      }
   685→    },
   686→
   687→    // SELECT * FROM mentions WHERE brand_id = $1
   688→    mentions: async (_: unknown, args: { brandId?: string; first?: number; platform?: string; sentiment?: string }, context: GraphQLContext) => {
   689→      context.requireAuth();
   690→      try {
   691→        const limit = args.first || 50;
   692→
   693→        const whereConditions = [];
   694→        if (args.brandId) {
   695→          whereConditions.push(eq(schema.brandMentions.brandId, args.brandId));
   696→        }
   697→
   698→        const query = whereConditions.length > 0
   699→          ? db.select().from(schema.brandMentions).where(and(...whereConditions))
   700→          : db.select().from(schema.brandMentions);
   701→
   702→        const results = await query.orderBy(desc(schema.brandMentions.timestamp)).limit(limit);
   703→        const totalResult = args.brandId
   704→          ? await db.select({ count: count() }).from(schema.brandMentions).where(eq(schema.brandMentions.brandId, args.brandId))
   705→          : await db.select({ count: count() }).from(schema.brandMentions);
   706→        const total = totalResult[0]?.count || 0;
   707→
   708→        return {
   709→          edges: results.map((mention, idx) => ({
   710→            node: {
   711→              ...mention,
   712→              sentimentScore: mention.sentiment === "positive" ? 0.8 : mention.sentiment === "negative" ? 0.2 : 0.5,
   713→              isRecommendation: mention.promptCategory === "recommendation",
   714→              competitorMentioned: (mention.competitors || []).length > 0,
   715→            },
   716→            cursor: Buffer.from(`mention:${idx}`).toString("base64"),
   717→          })),
   718→          pageInfo: {
   719→            hasNextPage: results.length === limit,
   720→            hasPreviousPage: false,
   721→            startCursor: results.length > 0 ? Buffer.from("mention:0").toString("base64") : null,
   722→            endCursor: results.length > 0 ? Buffer.from(`mention:${results.length - 1}`).toString("base64") : null,
   723→            total,
   724→          },
   725→          stats: {
   726→            total,
   727→            byPlatform: {},
   728→            bySentiment: {},
   729→            avgPosition: null,
   730→          },
   731→        };
   732→      } catch (error) {
   733→        console.error("Database error fetching mentions:", error);
   734→        throw new Error("Failed to fetch mentions. Please try again later.");
   735→      }
   736→    },
   737→
   738→    // GEO Score - calculated from brand mentions and recommendations
   739→    geoScore: async (_: unknown, { brandId }: { brandId: string }, context: GraphQLContext) => {
   740→      context.requireAuth();
   741→
   742→      // Get mention stats for the brand
   743→      const mentionsResult = await db.select({ count: count() }).from(schema.brandMentions).where(eq(schema.brandMentions.brandId, brandId));
   744→      const mentionCount = mentionsResult[0]?.count || 0;
   745→
   746→      // Get recommendation stats
   747→      const recsResult = await db.select({ count: count() }).from(schema.recommendations).where(eq(schema.recommendations.brandId, brandId));
   748→      const recCount = recsResult[0]?.count || 0;
   749→
   750→      // Calculate a simple GEO score based on available data
   751→      const visibilityScore = Math.min(100, mentionCount * 5);
   752→      const sentimentScore = 70; // Default until we analyze sentiment distribution
   753→      const recommendationScore = Math.max(0, 100 - recCount * 5);
   754→      const overallScore = Math.round((visibilityScore * 0.4 + sentimentScore * 0.3 + recommendationScore * 0.3));
   755→
   756→      return {
   757→        id: `geo_${brandId}`,
   758→        brandId,
   759→        overallScore,
   760→        visibilityScore,
   761→        sentimentScore,
   762→        recommendationScore,
   763→        competitorGapScore: 50,
   764→        platformScores: {},
   765→        previousScore: null,
   766→        trend: 0,
   767→        calculatedAt: new Date().toISOString(),
   768→      };
   769→    },
   770→
   771→    // GEO Score history - query for direct access
   772→    geoScoreHistory: async (_: unknown, { brandId, days }: { brandId: string; days?: number }, context: GraphQLContext) => {
   773→      context.requireAuth();
   774→      const limit = days || 30;
   775→      const startDate = new Date(Date.now() - limit * 24 * 60 * 60 * 1000);
   776→
   777→      const historyData = await db
   778→        .select()
   779→        .from(schema.geoScoreHistory)
   780→        .where(
   781→          and(
   782→            eq(schema.geoScoreHistory.brandId, brandId),
   783→            sql`${schema.geoScoreHistory.calculatedAt} >= ${startDate}`
   784→          )
   785→        )
   786→        .orderBy(desc(schema.geoScoreHistory.calculatedAt))
   787→        .limit(limit);
   788→
   789→      return historyData.map((h) => ({
   790→        date: h.calculatedAt.toISOString(),
   791→        score: h.overallScore,
