     7→ * Usage:
     8→ * ```typescript
     9→ * import { beforeEach, describe, it, expect } from "vitest";
    10→ * import { setupGraphQLTest, mockSelectResult, mockInsertResult } from "../setup";
    11→ * import { createMockBrand, createMockGraphQLContext } from "../factories";
    12→ *
    13→ * describe("Brand Resolvers", () => {
    14→ *   const { getDb, getSchema, getContext, resetMocks } = setupGraphQLTest();
    15→ *
    16→ *   beforeEach(() => {
    17→ *     resetMocks();
    18→ *   });
    19→ *
    20→ *   it("should fetch a brand by ID", async () => {
    21→ *     const mockBrand = createMockBrand();
    22→ *     mockSelectResult([mockBrand]);
    23→ *
    24→ *     // Test resolver...
    25→ *   });
    26→ * });
    27→ * ```
