    73→ * Creates and configures all mocks needed for testing GraphQL resolvers.
    74→ * Call this at the top of your test file.
    75→ *
    76→ * @returns Object containing mock instances and utility functions
    77→ */
    78→export function setupGraphQLTest(options: { autoReset?: boolean } = {}) {
    79→  const { autoReset = false } = options;
    80→
    81→  // Initialize mocks
    82→  dbMock = createDbMock();
    83→  schemaMock = createSchemaMock();
