   104→    /**
   105→     * Get the mocked GraphQL context
   106→     */
   107→    getContext: () => contextMock,
   108→
   109→    /**
   110→     * Create a new context with custom values
   111→     */
   112→    createContext: (overrides: Partial<MockGraphQLContext> = {}) => {
   113→      contextMock = createMockGraphQLContext(overrides);
