     1→/**
     2→ * Integration Test Setup
     3→ *
     4→ * Provides test infrastructure for integration testing against a real database.
     5→ * Uses test transactions for isolation and automatic rollback.
     6→ *
     7→ * Environment Setup:
     8→ * - Set TEST_DATABASE_URL for dedicated test database (recommended)
     9→ * - Falls back to DATABASE_URL if TEST_DATABASE_URL is not set
    10→ *
    11→ * Usage:
    12→ * ```typescript
    13→ * import { describe, it, beforeAll, afterAll, beforeEach, afterEach } from "vitest";
    14→ * import { setupIntegrationTest } from "./setup";
    15→ * import { seedOrganization, seedBrandWithData } from "./seed";
    16→ *
    17→ * describe("Brand Integration Tests", () => {
    18→ *   const { getDb, getSchema, cleanup, seedTestData } = setupIntegrationTest();
    19→ *
    20→ *   beforeAll(async () => {
    21→ *     await seedTestData();
    22→ *   });
    23→ *
    24→ *   afterAll(async () => {
    25→ *     await cleanup();
    26→ *   });
    27→ *
    28→ *   it("should fetch a brand", async () => {
    29→ *     const db = getDb();
    30→ *     const result = await db.select().from(schema.brands);
    31→ *     expect(result.length).toBeGreaterThan(0);
    32→ *   });
    33→ * });
    34→ * ```
    35→ */
    36→
    37→import { neon, type NeonQueryFunction } from "@neondatabase/serverless";
    38→import { drizzle, type NeonHttpDatabase } from "drizzle-orm/neon-http";
    39→import { sql, eq, and, or, inArray } from "drizzle-orm";
    40→import { afterAll, beforeAll, beforeEach } from "vitest";
    41→import * as schema from "../../src/lib/db/schema";
    42→import type { SeedResult } from "./seed";
    43→import { createTestSeedData, cleanupTestData, TEST_IDS } from "./seed";
    44→
    45→// Export schema types for use in tests
    46→export type IntegrationTestSchema = typeof schema;
    47→export type IntegrationDatabase = NeonHttpDatabase<typeof schema>;
    48→
    49→// Database connection singleton
    50→let _sql: NeonQueryFunction<boolean, boolean> | null = null;
    51→let _db: NeonHttpDatabase<typeof schema> | null = null;
    52→
    53→// Track seeded data for cleanup
    54→let _seededData: SeedResult | null = null;
    55→
    56→/**
    57→ * Get the test database URL
    58→ * Prefers TEST_DATABASE_URL for dedicated test database
    59→ */
    60→function getTestDatabaseUrl(): string {
    61→  const testUrl = process.env.TEST_DATABASE_URL;
    62→  const devUrl = process.env.DATABASE_URL;
    63→
    64→  if (testUrl) {
    65→    return testUrl;
    66→  }
    67→
    68→  if (devUrl && devUrl !== "postgresql://placeholder") {
    69→    // Warn if using development database
    70→    console.warn(
    71→      "⚠️  TEST_DATABASE_URL not set - using DATABASE_URL for integration tests"
    72→    );
    73→    console.warn(
    74→      "   Consider setting TEST_DATABASE_URL to a dedicated test database"
    75→    );
    76→    return devUrl;
    77→  }
    78→
    79→  throw new Error(
    80→    "Integration tests require TEST_DATABASE_URL or DATABASE_URL to be set.\n" +
    81→      "Set either:\n" +
    82→      "  - TEST_DATABASE_URL: Dedicated test database (recommended)\n" +
    83→      "  - DATABASE_URL: Development database (will be used if TEST_DATABASE_URL not set)"
    84→  );
    85→}
    86→
    87→/**
    88→ * Check if database is configured for integration tests
    89→ */
    90→export function isDatabaseConfigured(): boolean {
    91→  try {
    92→    getTestDatabaseUrl();
    93→    return true;
    94→  } catch {
    95→    return false;
    96→  }
    97→}
    98→
    99→/**
   100→ * Get the database instance for integration tests
   101→ * Creates a singleton connection that's reused across tests
   102→ */
   103→export function getIntegrationDb(): NeonHttpDatabase<typeof schema> {
   104→  if (!_db) {
   105→    const url = getTestDatabaseUrl();
   106→    _sql = neon(url);
   107→    _db = drizzle(_sql, { schema });
   108→  }
   109→  return _db;
   110→}
   111→
   112→/**
   113→ * Get the schema for direct table access
   114→ */
   115→export function getSchema(): typeof schema {
   116→  return schema;
   117→}
   118→
   119→/**
   120→ * Test context with authentication info
   121→ */
   122→export interface TestContext {
   123→  userId: string;
   124→  orgId: string;
   125→  clerkUserId: string;
   126→  requireAuth: () => { userId: string; orgId: string };
   127→}
   128→
   129→/**
   130→ * Create a test context for resolver testing
   131→ */
   132→export function createTestContext(overrides: Partial<TestContext> = {}): TestContext {
   133→  const orgId = overrides.orgId ?? TEST_IDS.ORG;
   134→  const userId = overrides.userId ?? TEST_IDS.USERS[0];
   135→  const clerkUserId = overrides.clerkUserId ?? `clerk_test_${userId}`;
   136→
   137→  return {
   138→    userId,
   139→    orgId,
   140→    clerkUserId,
   141→    requireAuth: () => ({ userId, orgId }),
   142→  };
   143→}
   144→
   145→/**
   146→ * Clean up all test data from the database
   147→ * Should be called after test suite completes
   148→ */
   149→export async function cleanupAllTestData(): Promise<void> {
   150→  const db = getIntegrationDb();
   151→
   152→  try {
   153→    // Clean up using the stored seeded data IDs
   154→    if (_seededData) {
   155→      await cleanupTestData(db, _seededData);
   156→      _seededData = null;
   157→    }
   158→
   159→    // Also clean up any orphaned test data using prefix pattern
   160→    await cleanupByTestPrefix(db);
   161→  } catch (error) {
   162→    console.error("Cleanup failed:", error);
   163→    throw error;
   164→  }
   165→}
   166→
   167→/**
   168→ * Clean up test data by known test ID prefixes
   169→ * Used as a fallback to ensure no test data persists
   170→ */
   171→async function cleanupByTestPrefix(db: IntegrationDatabase): Promise<void> {
   172→  // Delete test organization which cascades to related data
   173→  try {
   174→    await db
