   186→  } catch {
   187→    // May not exist, ignore
   188→  }
   189→}
   190→
   191→/**
   192→ * Seed test data into the database
   193→ * Returns the seeded data IDs for reference in tests
   194→ */
   195→export async function seedTestData(): Promise<SeedResult> {
   196→  const db = getIntegrationDb();
   197→
   198→  // Clean up any existing test data first
   199→  await cleanupAllTestData();
   200→
   201→  // Create fresh test data
   202→  _seededData = await createTestSeedData(db);
