   204→  return _seededData;
   205→}
   206→
   207→/**
   208→ * Get the currently seeded test data
   209→ */
   210→export function getSeededData(): SeedResult | null {
   211→  return _seededData;
   212→}
   213→
   214→/**
   215→ * Main setup function for integration tests
